const express = require('express');
const app = express();
const bodyParser = require('body-parser');
const { v4: uuidv4 } = require('uuid');

let levelsData = [
  // Level data structure example:
  // { id: 'level1', scoreToWin: 20, timeLimit: 60 },
];

let rewardsData = [
  // Reward data structure example:
  // { id: 'reward1', points: 100, item: 'New Piece' },
];

app.use(bodyParser.json());

// Level completion endpoint
app.post('/level/complete', (req, res) => {
  const { levelId, score, time } = req.body;
  const userId = uuidv4(); // You could use a real user ID system

  // Find the level and check the conditions
  const level = levelsData.find(level => level.id === levelId);
  if (!level) {
    return res.status(404).send({ error: 'Level not found' });
  }

  if (score < level.scoreToWin || time > level.timeLimit) {
    return res.status(400).send({ error: 'Invalid level completion data' });
  }

  // Award rewards based on client-reported metrics (dummy example)
  const rewards = [];
  if (score > 50) rewards.push(rewardsData[0].id);
  if (time < level.timeLimit * 0.8) rewards.push(rewardsData[1].id);

  // Save user scores and rewards
  // You could use a real database to store data
  const userData = { userId, scores: [levelId], rewards };
  usersData.push(userData);

  res.send({ message: 'Level completed successfully!' });
});

// Reward claim endpoint
app.post('/reward/claim', (req, res) => {
  const { userId } = req.body;

  // Find the user and check rewards
  const user = usersData.find(user => user.userId === userId);
  if (!user) {
    return res.status(404).send({ error: 'User not found' });
  }

  // Award claimed rewards (dummy example)
  const claimedRewards = [];
  user.rewards.forEach(rewardId => {
    const rewardIndex = rewardsData.findIndex(reward => reward.id === rewardId);
    if (rewardIndex !== -1) {
      claimedRewards.push(rewardsData[rewardIndex]);
      user.rewards.splice(rewardIndex, 1); // Remove claimed reward from user data
    }
  });

  res.send({ message: 'Rewards claimed successfully!', rewards: claimedRewards });
});

app.listen(3000, () => console.log('Server running on port 3000'));